  ('aviation-6c581c7e-moex-00075', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依現行規定，有關國家重要事項之決策權，下列敘述何者錯誤？', '["立法院有議決之權，但行政院無法透過覆議制度推翻", "行政院院長或部會首長應提出報告並備質詢，惟立法院得議決是否聽取報告", "若行政院院長報告並備質詢後，立法院仍議決不予支持，行政院院長得自行辭職以示負責", "若涉及法律修正，應該由行政院向立法院提出法律修正案，由立法院審議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00076', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依現行規定，下列有關監察院之敘述何者正確？', '["監察委員在院內所為之言論及表決，對院外不負責任", "監察委員，除現行犯外，非經監察院許可，不得逮捕或拘禁", "監察委員不得兼任其他公職或執行業務", "監察院設審計長，審計長應於行政院提出決算後3個月內，依法完成其審核，並提出審核報告於監察院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00077', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '關於司法院大法官，下列敘述何者錯誤？', '["司法院大法官有統一解釋法令及解釋憲法之權限", "大法官由總統提名，經立法院同意任命之", "大法官除法官轉任者外，不適用法官終身職待遇之規定", "司法院院長享有8年任期之保障"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00078', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '依憲法訴訟法之規定，關於「國家機關聲請法規範違憲」之「聲請人」，下列敘述何者錯誤？', '["中央選舉委員會於其獨立行使職權之範圍內，可以作為聲請人", "臺北市政府就委辦事項的範圍內，應報請行政院，由行政院作為聲請人", "總統府作為國家最高機關，可以作為聲請人", "考試院就其作為考試事項的國家最高機關，可以作為聲請人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
  ('aviation-6c581c7e-moex-00079', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '電子遊戲場業管理條例第9條第1項規定「電子遊戲場業營業場所應距離國民中、小學、高中、職校、 醫院50公尺以上。」依司法院大法官解釋，下列敘述何者錯誤？', '["上述距離限制，係對從事工作地點之執行職業自由之限制", "上開規定係保留地方因地制宜空間所設之最低標準，故直轄市、縣（市）得另以自治條例為應保持 更長距離之規範", "各直轄市、縣（市）基於因地制宜政策考量而以自治條例設定較長之距離規定，係屬必要之手段", "直轄市、縣（市）自治條例之距離限制規定，如超出法定最低限制較多時，縱使可能產生實質阻絕 之效果，亦不違反比例原則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL),
