  ('aviation-6c581c7e-moex-00083', 'aviation-6c581c7e', 'aviation-6c581c7e-moex-112-7bf35b0f', 'sub-aviation-6c581c7e-04', NULL, 'single_choice', '某甲向主管機關申請營業許可，於主管機關受理後，處理程序終結前，相關法規有所修改。依舊規定 甲之申請應予許可，然依新規定甲尚須補足相關條件方有可能通過。此際主管機關應如何適用法規？', '["應適用舊法規", "應適用新法規", "由主管機關自行決定", "由主管機關之上級機關決定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:04+00:00", "source_pdf_sha1": "f79244208669", "answer_pdf_sha1": "b0e444a8d54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "401", "s": "0607", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識(包括中華民國憲法、法學緒論)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "aviation", "civil_category": "飛航諮詢"}'::jsonb, NULL)
